# Before retirement: flag check present
async def summarise(text: str, user_id: str) -> str:
    if registry.is_enabled_for("ai_summariser_v2", user_id):
        return await ai_summariser_v2.run(text)
    else:
        return legacy_summariser.run(text)


# After retirement: flag removed, AI behaviour is hardened
async def summarise(text: str) -> str:
    return await ai_summariser_v2.run(text)

# Steps for flag retirement:
# 1. Confirm rollout_pct == 100 and stable for ≥ 72h
# 2. Remove the flag check from all code call sites
# 3. Delete the legacy handler (if no longer used elsewhere)
# 4. Delete the flag from the flag store
